import React from "react";
import { motion } from "framer-motion";
import "bootstrap/dist/css/bootstrap.min.css";

export default function LandingPage() {
  return (
    <div>
      <nav className="navbar navbar-expand-lg navbar-light bg-light sticky-top shadow-sm">
        <div className="container">
          <a className="navbar-brand fw-bold" href="#">Techvruk</a>
        </div>
      </nav>

      <section className="text-center text-white d-flex align-items-center" style={{ height: "90vh", background: "linear-gradient(90deg,#2563eb,#7c3aed)" }}>
        <div className="container">
          <motion.h1 initial={{ opacity: 0, y: -20 }} animate={{ opacity: 1, y: 0 }} className="display-4 fw-bold">
            Build the Future with Techvruk
          </motion.h1>
        </div>
      </section>

      <footer className="bg-dark text-white text-center py-3">
        <p>© 2026 Techvruk</p>
      </footer>
    </div>
  );
}
